import math
from semantic_kernel.functions import kernel_function
from semantic_kernel import Kernel

class MathPlugin:
    @kernel_function(name="square_root", description="Compute the square root of a number")
    def square_root(self, number: float) -> float:
        return math.sqrt(number)

    @kernel_function(name="power", description="Raise base to an exponent")
    def power(self, base: float, exponent: float) -> float:
        return base ** exponent

kernel = Kernel()
kernel.add_plugin(MathPlugin(), plugin_name="math")

# Invoke by plugin/function name
result = await kernel.invoke("math", "square_root", number=16.0)
print(result)   # 4.0

from semantic_kernel.planners.function_calling_stepwise_planner import (
    FunctionCallingStepwisePlanner,
    FunctionCallingStepwisePlannerOptions,
)

planner = FunctionCallingStepwisePlanner(
    service_id="chat",
    options=FunctionCallingStepwisePlannerOptions(max_iterations=5),
)

result = await planner.invoke(kernel, "What is 3 to the power of 4 plus its square root?")
print(result.final_answer)   # "81 + 9 = 90"

from tenacity import retry, stop_after_attempt, wait_exponential
from semantic_kernel.exceptions import KernelInvokeException

@retry(stop=stop_after_attempt(3), wait=wait_exponential(min=1, max=10))
async def safe_invoke(kernel, plugin, function, **kwargs):
    try:
        return await kernel.invoke(plugin, function, **kwargs)
    except KernelInvokeException as e:
        print(f"Kernel error: {e}")
        raise   # tenacity re-raises after exhausting retries
